window.toggleCards = function(className, btnElement, textShow, textHide) {
    const elements = document.querySelectorAll('.' + className);
    if (elements.length === 0) return;
    const isHidden = elements[0].style.display === 'none';
    elements.forEach(el => {
        el.style.display = isHidden ? '' : 'none';
    });
    btnElement.innerHTML = isHidden ? textHide : textShow;
    btnElement.setAttribute('aria-expanded', isHidden ? 'true' : 'false');
};

;
/* enhancements.js */
/* ============================================================
   ENHANCEMENTS.JS — Futuristic 3D & Visual Layer (Optimized)
   REMOVED: Duplicate IntersectionObserver (handled by futuristic-global.js)
   REMOVED: WhatsApp magnetic pull (ran Math.hypot on every global mousemove)
   OPTIMIZED: All mousemove handlers throttled via requestAnimationFrame
   OPTIMIZED: Heavy init wrapped in requestIdleCallback where available
   PRESERVED: Hero tilt, card tilt, countdown tick, section stagger,
              sticky CTA strip, click tracking, section title underline
   ============================================================ */

document.addEventListener('DOMContentLoaded', function () {

  var IS_MOBILE    = window.matchMedia('(max-width: 768px)').matches;
  var PREFERS_RED  = window.matchMedia('(prefers-reduced-motion: reduce)').matches;
  var DISABLE_3D   = IS_MOBILE || PREFERS_RED;

  /* ============================================================
     1. HERO CARD — Interactive 3D Tilt (rAF throttled)
  ============================================================ */
  if (!DISABLE_3D) {
    var heroCard   = document.querySelector('.hero-main-card');
    var heroVisual = document.querySelector('.hero-visual');

    if (heroCard && heroVisual) {
      heroCard.classList.add('tilt-3d');
      var tiltRaf = false;

      heroVisual.addEventListener('mousemove', function (e) {
        if (tiltRaf) return;
        tiltRaf = true;
        requestAnimationFrame(function () {
          var rect = heroVisual.getBoundingClientRect();
          var cx   = rect.left + rect.width  / 2;
          var cy   = rect.top  + rect.height / 2;
          var dx   = (e.clientX - cx) / (rect.width  / 2);
          var dy   = (e.clientY - cy) / (rect.height / 2);
          var rotX = -(dy * 6).toFixed(1);
          var rotY =  (dx * 7).toFixed(1);
          heroCard.style.transform =
            'perspective(900px) rotateX(' + rotX + 'deg) rotateY(' + rotY + 'deg) scale(1.01)';
          tiltRaf = false;
        });
      });

      heroVisual.addEventListener('mouseleave', function () {
        heroCard.style.transform = '';
        tiltRaf = false;
      });
    }
  }

  /* ============================================================
     2. HERO SECTION PARALLAX — cursor-reactive depth (rAF throttled)
  ============================================================ */
  if (!DISABLE_3D) {
    var heroSection  = document.querySelector('.hero');
    var heroVisualEl = document.querySelector('.hero-visual');

    if (heroSection && heroVisualEl && !heroVisualEl.classList.contains('parallax-hero')) {
      heroVisualEl.classList.add('parallax-hero');
      var parallaxRaf = false;

      heroSection.addEventListener('mousemove', function (e) {
        if (parallaxRaf) return;
        parallaxRaf = true;
        requestAnimationFrame(function () {
          var rect = heroSection.getBoundingClientRect();
          var dx   = (e.clientX - rect.left - rect.width  / 2) / rect.width;
          var dy   = (e.clientY - rect.top  - rect.height / 2) / rect.height;
          heroVisualEl.style.transform =
            'translate3d(' + (dx * -12).toFixed(1) + 'px, ' +
            (dy * -9).toFixed(1) + 'px, 0)';
          parallaxRaf = false;
        });
      });

      heroSection.addEventListener('mouseleave', function () {
        heroVisualEl.style.transform = '';
        parallaxRaf = false;
      });
    }
  }

  /* ============================================================
     3. CARD MICRO-TILT — rAF throttled per-card tilt
  ============================================================ */
  if (!DISABLE_3D) {
    var tiltTargets = document.querySelectorAll(
      '.why-card, .testi-card, .project-card, .hl-card, .daily-card'
    );

    tiltTargets.forEach(function (card) {
      var cardRaf = false;
      card.addEventListener('mousemove', function (e) {
        if (cardRaf) return;
        cardRaf = true;
        requestAnimationFrame(function () {
          var r  = card.getBoundingClientRect();
          var dx = (e.clientX - r.left - r.width  / 2) / (r.width  / 2);
          var dy = (e.clientY - r.top  - r.height / 2) / (r.height / 2);
          card.style.transform =
            'perspective(700px) rotateX(' + (-dy * 3.5).toFixed(1) + 'deg) rotateY(' +
            (dx * 4.5).toFixed(1) + 'deg) translateY(-6px)';
          cardRaf = false;
        });
      });

      card.addEventListener('mouseleave', function () {
        card.style.transform = '';
        cardRaf = false;
      });
    });
  }

  /* ============================================================
     4. COUNTDOWN TICK — Momentary .cd-tick class
        Does NOT touch countdown logic in script.js
  ============================================================ */
  (function () {
    var cdIds    = ['cd-d', 'cd-h', 'cd-m', 'cd-s'];
    var lastVals = {};

    function checkTick() {
      cdIds.forEach(function (id) {
        var el = document.getElementById(id);
        if (!el) return;
        var val = el.textContent;
        if (val !== lastVals[id]) {
          var unit = el.closest('.countdown-unit');
          if (unit) {
            unit.classList.add('cd-tick');
            setTimeout(function () { unit.classList.remove('cd-tick'); }, 200);
          }
          lastVals[id] = val;
        }
      });
    }

    setInterval(checkTick, 900);
  }());

  /* ============================================================
     5. STAGGER FADE-UP — incremental transition-delay on siblings
  ============================================================ */
  var staggerParents = document.querySelectorAll(
    '.why-grid, .highlights-grid, .projects-grid, .trust-grid, .testimonials-grid, .daily-grid'
  );

  staggerParents.forEach(function (grid) {
    var children = grid.querySelectorAll('.fade-up');
    children.forEach(function (child, i) {
      if (!child.dataset.staggered) {
        child.style.transitionDelay = Math.min(i * 80, 350) + 'ms';
        child.dataset.staggered = '1';
      }
    });
  });

  /* ============================================================
     6. SECTION TITLE UNDERLINE — scroll-triggered width animation
  ============================================================ */
  if (!PREFERS_RED) {
    var sectionTitles = document.querySelectorAll('.section-title');
    var titleObs = new IntersectionObserver(function (entries) {
      entries.forEach(function (entry) {
        if (entry.isIntersecting) {
          entry.target.classList.add('title-visible');
          titleObs.unobserve(entry.target);
        }
      });
    }, { threshold: 0.3 });

    sectionTitles.forEach(function (t) { titleObs.observe(t); });
  }

  /* ============================================================
     7. STICKY CTA STRIP — injected bottom bar
        Appears after 40% scroll. Dismissible via close button.
  ============================================================ */
  (function () {
    var STRIP_ID      = 'sds-sticky-strip';
    var DISMISSED_KEY = 'sds_strip_dismissed';

    if (sessionStorage.getItem(DISMISSED_KEY)) return;
    if (document.getElementById(STRIP_ID)) return;

    var basePath = '';
    var fb = document.getElementById('file-protocol-fallback');
    if (fb && fb.getAttribute('data-depth')) {
      var depth = parseInt(fb.getAttribute('data-depth'), 10) || 0;
      for (var i = 0; i < depth; i++) basePath += '../';
    } else {
      var segments = window.location.pathname.split('/').filter(Boolean);
      if (segments.length > 0 && segments[segments.length - 1].indexOf('.') !== -1) {
        segments.pop();
      }
      var depth = segments.length;
      for (var i = 0; i < depth; i++) basePath += '../';
    }
    var demoHref = basePath + 'contact/book-demo.html';

    var strip = document.createElement('div');
    strip.id  = STRIP_ID;
    strip.className = 'sticky-cta-strip';
    var batchText = (window.CONFIG && window.CONFIG.batchName) || 'June 2026 Batch';
    strip.innerHTML =
      '<p>🔥 Limited seats left for ' + batchText + '!</p>' +
      '<a href="' + demoHref + '" class="strip-cta">Book Free Demo</a>' +
      '<button class="strip-close" aria-label="Close">✕</button>';
    document.body.appendChild(strip);

    strip.querySelector('.strip-close').addEventListener('click', function () {
      strip.classList.remove('visible');
      sessionStorage.setItem(DISMISSED_KEY, '1');
    });

    strip.querySelector('.strip-cta').addEventListener('click', function () {
      strip.classList.remove('visible');
      sessionStorage.setItem(DISMISSED_KEY, '1');
    });

    var shown = false;
    function handleStripScroll() {
      if (sessionStorage.getItem(DISMISSED_KEY)) return;
      var scrollPct  = window.scrollY / (document.body.scrollHeight - window.innerHeight);
      var nearFooter = window.scrollY + window.innerHeight > document.body.scrollHeight - 200;

      if (scrollPct > 0.40 && !nearFooter) {
        if (!shown) { strip.classList.add('visible'); shown = true; }
      } else {
        strip.classList.remove('visible');
        shown = false;
      }
    }

    window.addEventListener('scroll', handleStripScroll, { passive: true });
  }());

  /* ============================================================
     END — All enhancements isolated. Zero side-effects.
  ============================================================ */
});

;
/* color-dynamics.js */
/* ============================================================
   COLOR-DYNAMICS.JS — Dynamic Color Layer (Optimized)
   REMOVED: updateProximity() rAF loop (getBoundingClientRect on
            every card every mousemove frame = very expensive)
   REMOVED: countdown MutationObserver (low value, high overhead)
   REMOVED: button press inline style manipulation
   KEPT: class injection (cd-glow, cd-card, cd-btn-shift setup)
   KEPT: hero stat icon hover (event-driven = efficient)
   ============================================================ */

document.addEventListener('DOMContentLoaded', function () {

  var IS_MOBILE   = window.matchMedia('(max-width: 768px)').matches;
  var PREFERS_RED = window.matchMedia('(prefers-reduced-motion: reduce)').matches;

  /* ============================================================
     1. ADD .cd-glow to glow-eligible elements
  ============================================================ */
  document.querySelectorAll('.seats-badge, .section-tag, .float-card').forEach(function (el) {
    el.classList.add('cd-glow');
  });

  /* ============================================================
     2. ADD .cd-card + stagger offset to interactive cards
  ============================================================ */
  var cardSelectors = [
    '.why-card', '.hl-card', '.testi-card',
    '.project-card', '.trust-card', '.daily-card'
  ];
  document.querySelectorAll(cardSelectors.join(',')).forEach(function (card, i) {
    card.classList.add('cd-card');
    card.style.setProperty('--cd-stagger', (i % 6) * 0.55 + 's');
  });

  /* ============================================================
     3. ADD .cd-btn-shift to CTA buttons
  ============================================================ */
  document.querySelectorAll('.btn-primary, .btn-yellow, .btn-ghost').forEach(function (btn) {
    btn.classList.add('cd-btn-shift');
  });

  /* ============================================================
     4. HERO BACKGROUND COLOR FLOW — inject .cd-hero-orb div
  ============================================================ */
  var hero = document.querySelector('.hero');
  if (hero && !document.querySelector('.cd-hero-orb')) {
    var orb = document.createElement('div');
    orb.className = 'cd-hero-orb';
    hero.insertBefore(orb, hero.firstChild);
  }

  /* ============================================================
     5. PREMIUM CARD REFLECT
  ============================================================ */
  document.querySelectorAll(
    '.hero-main-card, .form-wrapper, .pricing-card, .level-card'
  ).forEach(function (el) {
    el.classList.add('cd-reflect');
  });

  /* ============================================================
     6. HERO STAT ICONS — hover-only color accent (event-driven)
  ============================================================ */
  document.querySelectorAll('.hero-stat-icon').forEach(function (icon) {
    icon.addEventListener('mouseenter', function () {
      icon.style.boxShadow = '0 0 14px rgba(6,182,212,.45), 0 0 28px rgba(6,182,212,.15)';
      icon.style.transition = 'box-shadow .28s ease, transform .28s ease';
    });
    icon.addEventListener('mouseleave', function () {
      icon.style.boxShadow = '';
    });
  });

  /* ============================================================
     END — Fully isolated. Zero side-effects on existing code.
  ============================================================ */
});

;
/* futuristic-global.js */
/**
 * futuristic-global.js — Site-Wide Futuristic Layer (Optimized)
 * Scroll reveal, sticky header, smooth scroll, mobile nav
 * REMOVED: ambient particle system (filter:blur expensive paint)
 * OPTIMIZED: Consolidated observers, passive scroll listeners
 */

(function () {
  'use strict';

  /* ── 1. Sticky Header scroll class ── */
  const header = document.getElementById('mainHeader');
  if (header) {
    const onScroll = () => {
      if (window.scrollY > 40) header.classList.add('scrolled');
      else header.classList.remove('scrolled');
    };
    window.addEventListener('scroll', onScroll, { passive: true });
    onScroll();
  }

  /* ── 2. Unified Scroll-reveal: .fg-reveal and .fade-up ── */
  const revealEls = document.querySelectorAll('.fg-reveal, .fade-up');
  if (revealEls.length) {
    const io = new IntersectionObserver((entries) => {
      entries.forEach(e => {
        if (e.isIntersecting) {
          e.target.classList.add('fg-visible', 'visible');
          io.unobserve(e.target);
        }
      });
    }, { threshold: 0.10, rootMargin: '0px 0px -30px 0px' });
    revealEls.forEach(el => io.observe(el));
  }

  /* ── 3. Section title underline trigger ── */
  const titles = document.querySelectorAll('.section-title');
  if (titles.length) {
    const tio = new IntersectionObserver((entries) => {
      entries.forEach(e => {
        if (e.isIntersecting) {
          e.target.classList.add('title-visible');
          tio.unobserve(e.target);
        }
      });
    }, { threshold: 0.2 });
    titles.forEach(t => tio.observe(t));
  }

  /* ── 4. Mobile nav toggle ── */
  const toggle = document.getElementById('mobileNavToggle');
  const menu   = document.getElementById('mobileNavMenu');
  const close  = document.getElementById('mobileNavClose');
  if (toggle && menu) {
    toggle.addEventListener('click', () => menu.classList.add('open'));
    if (close) close.addEventListener('click', () => menu.classList.remove('open'));
    menu.addEventListener('click', (e) => {
      if (e.target === menu) menu.classList.remove('open');
    });
  }

  /* ── 5. Dynamic class injection ── */
  const isMobile = () => window.innerWidth <= 768;

  function applyDynamicClasses() {
    if (isMobile()) return; // skip heavy effects on mobile

    document.querySelectorAll(
      '.why-card,.hl-card,.testi-card,.project-card,.trust-card,.daily-card,.review-card,.gallery-card'
    ).forEach((el, i) => {
      el.classList.add('cd-card');
      el.style.setProperty('--cd-stagger', (i * 0.45) + 's');
    });

    document.querySelectorAll('.seats-badge,.section-tag').forEach(el => {
      el.classList.add('cd-glow');
    });

    document.querySelectorAll('.btn-primary,.btn-yellow').forEach(el => {
      el.classList.add('cd-btn-shift');
    });

    document.querySelectorAll('.float-card').forEach(el => {
      el.classList.add('cd-glow');
    });

    // Hero orb injection
    const hero = document.querySelector('.hero, .page-hero');
    if (hero && !hero.querySelector('.cd-hero-orb')) {
      const orb = document.createElement('div');
      orb.className = 'cd-hero-orb';
      hero.appendChild(orb);
    }

    // Reflect on premium cards
    document.querySelectorAll(
      '.hero-main-card,.form-wrapper,.pricing-card,.level-card'
    ).forEach(el => {
      el.classList.add('cd-reflect');
    });
  }

  applyDynamicClasses();

  /* ── 6. Tilt 3D on hero card (desktop only, rAF throttled) ── */
  const tiltCard = document.querySelector('.hero-main-card');
  if (tiltCard && !isMobile()) {
    tiltCard.classList.add('tilt-3d', 'parallax-hero', 'cd-reflect');
    let rafPending = false;
    tiltCard.addEventListener('mousemove', (e) => {
      if (rafPending) return;
      rafPending = true;
      requestAnimationFrame(() => {
        const rect = tiltCard.getBoundingClientRect();
        const cx = rect.left + rect.width / 2;
        const cy = rect.top  + rect.height / 2;
        const dx = (e.clientX - cx) / (rect.width  / 2);
        const dy = (e.clientY - cy) / (rect.height / 2);
        tiltCard.style.transform = `perspective(900px) rotateX(${(-dy * 6).toFixed(1)}deg) rotateY(${(dx * 6).toFixed(1)}deg) translateZ(4px)`;
        rafPending = false;
      });
    });
    tiltCard.addEventListener('mouseleave', () => {
      tiltCard.style.transform = '';
      rafPending = false;
    });
  }

  /* ── 7. Smooth scroll for anchor links ── */
  document.querySelectorAll('a[href^="#"]').forEach(a => {
    a.addEventListener('click', (e) => {
      const id = a.getAttribute('href').slice(1);
      const target = document.getElementById(id);
      if (target) {
        e.preventDefault();
        target.scrollIntoView({ behavior: 'smooth', block: 'start' });
      }
    });
  });

  /* ── 8. fg-reveal: mark section cards for reveal ── */
  document.querySelectorAll(
    '.review-card, .gallery-card, article, .b2b-feature-card, .fg-card'
  ).forEach((el, i) => {
    if (!el.classList.contains('fg-reveal') && !el.classList.contains('fade-up')) {
      el.classList.add('fg-reveal');
      if (i % 3 === 1) el.classList.add('fg-reveal-delay-1');
      if (i % 3 === 2) el.classList.add('fg-reveal-delay-2');
    }
  });

  // Re-observe newly added fg-reveal elements
  const newReveal = document.querySelectorAll('.fg-reveal:not(.fg-visible)');
  if (newReveal.length) {
    const io2 = new IntersectionObserver((entries) => {
      entries.forEach(e => {
        if (e.isIntersecting) {
          e.target.classList.add('fg-visible');
          io2.unobserve(e.target);
        }
      });
    }, { threshold: 0.10, rootMargin: '0px 0px -30px 0px' });
    newReveal.forEach(el => io2.observe(el));
  }

})();

;
